    async fn remove_edges(&self, entry_id: &Uuid) -> Result<()> {
        sqlx::query("DELETE FROM edges WHERE from_id = $1 OR to_id = $1")
            .bind(entry_id)
            .execute(&self.pool)
            .await
            .map_err(|e| CorviaError::Storage(format!("Failed to remove edges: {e}")))?;

        Ok(())
    }
